import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function runMarketSurveillance(chainName, tokenAddress) {
  const prices = await client.PricingService.getTokenPrices(
    chainName, "USD", tokenAddress
  );
  const recentPrices = prices.data?.items?.slice(-24) ?? [];
  const avg = recentPrices.reduce((s, p) => s + (p.price ?? 0), 0) / recentPrices.length;
  const latest = recentPrices[recentPrices.length - 1]?.price ?? 0;
  const deviation = Math.abs(latest - avg) / avg;
  return { tokenAddress, avg, latest, deviation, alert: deviation > 0.1 };
}
